CREATE TABLE finance_sequences(tenant_id uuid NOT NULL REFERENCES tenants(id),organization_id uuid NOT NULL REFERENCES organizations(id),kind text NOT NULL CHECK(kind IN('order','invoice')),year integer NOT NULL,value integer NOT NULL CHECK(value>=1),PRIMARY KEY(tenant_id,organization_id,kind,year));
CREATE TABLE sales_orders(id uuid PRIMARY KEY,tenant_id uuid NOT NULL REFERENCES tenants(id),organization_id uuid NOT NULL REFERENCES organizations(id),site_id uuid NOT NULL REFERENCES sites(id),customer_id uuid NOT NULL REFERENCES customers(id),quote_id uuid NOT NULL REFERENCES quotes(id),number text NOT NULL,currency char(3) NOT NULL,total_cents integer NOT NULL,status text NOT NULL CHECK(status IN('confirmed','in_progress','completed','cancelled')),created_at timestamptz NOT NULL,UNIQUE(tenant_id,organization_id,number));
CREATE TABLE invoices(id uuid PRIMARY KEY,tenant_id uuid NOT NULL REFERENCES tenants(id),organization_id uuid NOT NULL REFERENCES organizations(id),site_id uuid NOT NULL REFERENCES sites(id),customer_id uuid NOT NULL REFERENCES customers(id),order_id uuid NOT NULL REFERENCES sales_orders(id),number text NOT NULL,currency char(3) NOT NULL,total_cents integer NOT NULL,paid_cents integer NOT NULL,balance_cents integer NOT NULL,status text NOT NULL CHECK(status IN('issued','partially_paid','paid','void')),issued_at timestamptz NOT NULL,due_at timestamptz NOT NULL,UNIQUE(tenant_id,organization_id,number),CHECK(total_cents=paid_cents+balance_cents));
CREATE TABLE payments(id uuid PRIMARY KEY,tenant_id uuid NOT NULL REFERENCES tenants(id),invoice_id uuid NOT NULL REFERENCES invoices(id),provider text NOT NULL,provider_reference text NOT NULL,idempotency_key text NOT NULL,amount_cents integer NOT NULL CHECK(amount_cents>0),currency char(3) NOT NULL,method text NOT NULL,status text NOT NULL CHECK(status IN('succeeded','failed','refunded')),received_at timestamptz NOT NULL,UNIQUE(tenant_id,idempotency_key));
CREATE INDEX invoices_due_idx ON invoices(tenant_id,status,due_at) WHERE status IN('issued','partially_paid');
DO $$ DECLARE n text;BEGIN FOREACH n IN ARRAY ARRAY['finance_sequences','sales_orders','invoices','payments'] LOOP EXECUTE format('ALTER TABLE %I ENABLE ROW LEVEL SECURITY',n);EXECUTE format('ALTER TABLE %I FORCE ROW LEVEL SECURITY',n);EXECUTE format('CREATE POLICY tenant_isolation ON %I USING (tenant_id=current_setting(''app.tenant_id'',true)::uuid) WITH CHECK (tenant_id=current_setting(''app.tenant_id'',true)::uuid)',n);END LOOP;END $$;
